-- Australia – Student Visa (Subclass 500) — 30 FAQs
-- Source: content/service-library/australia-student-visa.json

UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee Subclass 500 approval?","a":"No. Home Affairs assesses GS, funds, and eligibility. Strong files improve chances but approval is never guaranteed."},{"q":"What is GS requirement?","a":"Officers assess whether applicant is genuine student with credible study plan and intent to comply with visa conditions."},{"q":"How much funds to show?","a":"Verify current living cost amounts on homeaffairs.gov.au plus tuition and travel. Include credible source evidence."},{"q":"Can spouse join?","a":"Partner may apply for subsequent entrant or separate visa depending on circumstances—assess case-by-case."},{"q":"Can student work?","a":"Limited work hours during study—verify current conditions on Home Affairs website."},{"q":"When to apply?","a":"After CoE issued; allow processing time before course start."},{"q":"Is health exam mandatory?","a":"Depends on profile and country—follow Home Affairs health requirements."},{"q":"What after graduation?","a":"Discuss Subclass 485 Temporary Graduate visa eligibility separately."},{"q":"What is Description for this service?","a":"Subclass 500 student visa for full-time study at an Australian CRICOS-registered institution. Requires Confirmation of Enrolment (CoE) and online ImmiAccount application."},{"q":"What is Eligible applicants for this service?","a":"Valid CoE · Genuine Student requirement · Financial capacity · English proficiency · OSHC · Health and character requirements"},{"q":"What is Financial evidence for this service?","a":"Funds for tuition, travel, and living costs per Home Affairs guidelines. Amounts update periodically—verify before quoting."},{"q":"Important note on Financial evidence?","a":"Funds for tuition, travel, and living costs per Home Affairs guidelines. Amounts update periodically—verify before quoting."},{"q":"What is Key authority for this service?","a":"Department of Home Affairs (Australia)"},{"q":"What is After approval for this service?","a":"Maintain enrolment, OSHC, and visa conditions. Work limits apply during study period."},{"q":"Is CoE from CRICOS provider required?","a":"Must match intended course"},{"q":"Is Genuine Student (GS) requirement required?","a":"Study rationale and home ties"},{"q":"Is Financial capacity required?","a":"Per Home Affairs amounts"},{"q":"Is English proficiency required?","a":"IELTS/PTE per course level"},{"q":"Is OSHC for study duration required?","a":"Mandatory health cover"},{"q":"Is Health exam (if required) required?","a":"Assess whether Health exam (if required) is satisfied for this case."},{"q":"Is Police certificates (if required) required?","a":"Assess whether Police certificates (if required) is satisfied for this case."},{"q":"What is the Processing time?","a":"4–8w — Varies by sector"},{"q":"What is the Government fee?","a":"AUD $2,000 — Verify on homeaffairs.gov.au"},{"q":"What is the Our approval rate?","a":"86% — ~73% industry benchmark"},{"q":"What is the Required docs?","a":"14 — + OSHC & funds"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & OSHC"},{"q":"What if the client has Weak Genuine Student statement?","a":"Course-specific GS linking prior study/work to Australia program"},{"q":"Why is Weak Genuine Student statement a problem?","a":"Generic GS, course mismatch with background, unclear career plan."},{"q":"What if the client has Insufficient financial evidence?","a":"12-month funds per guidelines; sponsor ITR; loan evidence"},{"q":"Why is Insufficient financial evidence a problem?","a":"Unseasoned funds or amount below Home Affairs threshold."}]'::jsonb
),
updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000041';
